svg.script:
// 
(function(){
  var SVGNS='http://www.w3.org/2000/svg';
  function $(id){return document.getElementById(id);}
  function el(t,a){var e=document.createElementNS(SVGNS,t);for(var k in a)e.setAttribute(k,a[k]);return e;}

  var cx=640, cy=358, A=74, B=210, step=40, N=10;
  var Dscan=1600, Dmove=760;

  var patient=$('patient'), trails=$('trails');
  var beam=$('beam'), raysG=$('rays'), tube=$('tube'), det=$('detector');
  var active=$('activeTrace'), dirArrow=$('dirArrow');
  var sliceTxt=$('sliceTxt'), stateTxt=$('stateTxt'), dirTxt=$('dirTxt');
  var btnPlayLbl=$('btnPlayLbl'), btnSpeedLbl=$('btnSpeedLbl');

  // fan rays
  var rays=[]; for(var i=0;i<7;i++){var ln=el('line',{stroke:'#f5c400','stroke-width':1.3,'stroke-opacity':0.75}); raysG.appendChild(ln); rays.push(ln);}
  // progress dots
  var dots=[]; for(var i=0;i<N;i++){var c=el('circle',{cx:(946+i*30),cy:232,r:7,fill:'#ffffff',stroke:'#1b8a86','stroke-width':2}); $('progDots').appendChild(c); dots.push(c);}

  var state='scan', slice=0, dir=1, patientShift=0, tphase=0, last=null, running=true, speed=1, loop=true;

  function easeInOut(t){return t<0.5?2*t*t:1-Math.pow(-2*t+2,2)/2;}

  function arcPath(rx,ry,phi){
    var n=Math.max(2,Math.round(64*Math.abs(phi)/(2*Math.PI)));
    var d='';
    for(var i=0;i<=n;i++){var a=phi*i/n; var x=cx+rx*Math.sin(a); var y=cy-ry*Math.cos(a); d+=(i?'L':'M')+x.toFixed(1)+' '+y.toFixed(1)+' ';}
    return d;
  }

  function placeTube(g,px,py,z){
    var ang=Math.atan2(cy-py,cx-px)*180/Math.PI;
    var s=(1+0.20*z).toFixed(3);
    g.setAttribute('transform','translate('+px.toFixed(1)+' '+py.toFixed(1)+') rotate('+ang.toFixed(1)+') scale('+s+')');
    g.setAttribute('opacity',(0.62+0.38*(z+1)/2).toFixed(2));
  }

  function setDirArrow(){
    dirArrow.setAttribute('transform','translate('+cx+' '+(cy-B-34)+') '+(dir>0?'':'scale(-1,1)'));
  }

  function updateScan(phi){
    var tx=cx+A*Math.sin(phi), ty=cy-B*Math.cos(phi), tz=Math.sin(phi);
    var dx=cx-A*Math.sin(phi), dy=cy+B*Math.cos(phi), dz=-tz;
    placeTube(tube,tx,ty,tz); placeTube(det,dx,dy,dz);
    var vx=dx-tx, vy=dy-ty, L=Math.hypot(vx,vy)||1; vx/=L; vy/=L; var nx=-vy, ny=vx;
    var hw=70, tw=6;
    var pts=[[tx+nx*tw,ty+ny*tw],[dx+nx*hw,dy+ny*hw],[dx-nx*hw,dy-ny*hw],[tx-nx*tw,ty-ny*tw]];
    beam.setAttribute('points',pts.map(function(q){return q[0].toFixed(1)+','+q[1].toFixed(1);}).join(' '));
    beam.setAttribute('opacity',1);
    for(var i=0;i<rays.length;i++){
      var k=(i/(rays.length-1)-0.5)*2*hw; var ex=dx+nx*k, ey=dy+ny*k;
      rays[i].setAttribute('x1',tx.toFixed(1)); rays[i].setAttribute('y1',ty.toFixed(1));
      rays[i].setAttribute('x2',ex.toFixed(1)); rays[i].setAttribute('y2',ey.toFixed(1));
      rays[i].setAttribute('opacity',0.75);
    }
    active.setAttribute('d',arcPath(A,B,phi));
    active.setAttribute('opacity',1);
    sliceTxt.textContent='スライス  '+(slice+1)+' / '+N;
    stateTxt.textContent='回転撮影中（360°）';
    dirTxt.textContent='回転方向：'+(dir>0?'時計回り CW ↻':'反時計回り CCW ↺');
  }

  function hideBeam(o){
    beam.setAttribute('opacity',0);
    for(var i=0;i<rays.length;i++) rays[i].setAttribute('opacity',0);
    active.setAttribute('opacity',0);
    tube.setAttribute('opacity',o); det.setAttribute('opacity',o);
  }

  function addTrail(i){
    trails.appendChild(el('ellipse',{cx:(cx+i*step),cy:cy,rx:A,ry:B,fill:'none',stroke:'#2f9e44','stroke-width':2.4,'stroke-opacity':0.55}));
    dots[i].setAttribute('fill','#2f9e44'); dots[i].setAttribute('stroke','#1b6b34');
  }

  function prepSlice(){ active.setAttribute('d',''); setDirArrow(); }

  function showDone(){
    hideBeam(0.3);
    sliceTxt.textContent='撮影完了  10 / 10';
    stateTxt.textContent='10スライスを連続取得';
    dirTxt.textContent='シングルスライスCT（R-R方式）';
    if(loop) setTimeout(function(){ if(state==='done') resetAll(); }, 2400);
  }

  function resetAll(){
    while(trails.firstChild) trails.removeChild(trails.firstChild);
    for(var i=0;i<N;i++){dots[i].setAttribute('fill','#ffffff'); dots[i].setAttribute('stroke','#1b8a86');}
    slice=0; dir=1; patientShift=0; state='scan'; tphase=0; running=true;
    tube.setAttribute('opacity',1); det.setAttribute('opacity',1);
    prepSlice();
    patient.setAttribute('transform','translate(0,0)');
    btnPlayLbl.textContent='⏸ 一時停止';
  }

  function frame(now){
    if(last==null) last=now;
    var dt=(now-last)*speed; if(dt<0) dt=0; last=now;
    if(running) tphase+=dt;

    if(state==='scan'){
      var t=Math.min(1,tphase/Dscan);
      updateScan(2*Math.PI*dir*t);
      if(t>=1){ addTrail(slice); active.setAttribute('d',''); state='move'; tphase=0; }
    } else if(state==='move'){
      var tm=Math.min(1,tphase/Dmove);
      patientShift=slice*step+step*easeInOut(tm);
      hideBeam(0.35);
      sliceTxt.textContent='スライス  '+(slice+1)+' 撮影完了';
      stateTxt.textContent='寝台を頭側へ移動中 →';
      dirTxt.textContent='次は回転方向を反転';
      if(tm>=1){
        patientShift=(slice+1)*step; slice++; dir=-dir;
        if(slice>=N){ state='done'; showDone(); }
        else { state='scan'; tphase=0; prepSlice(); }
      }
    }
    patient.setAttribute('transform','translate('+(-patientShift).toFixed(1)+',0)');
    requestAnimationFrame(frame);
  }

  $('btnPlay').addEventListener('click',function(){ if(state==='done'){resetAll();return;} running=!running; btnPlayLbl.textContent=running?'⏸ 一時停止':'▶ 再生'; });
  $('btnReset').addEventListener('click',function(){ resetAll(); });
  $('btnSpeed').addEventListener('click',function(){ speed=(speed>=2)?1:(speed>=1.5?2:1.5); btnSpeedLbl.textContent='速度 x'+speed; });

  setDirArrow();
  requestAnimationFrame(frame);
})();
//
